import{f as l,D as A,o as a,c as E,a2 as o,b as e,w as r,a as s,G as n,a5 as i}from"./chunks/framework.DHYrF-q6.js";const P=JSON.parse('{"title":"AI PM 角色定位与三大方向","description":"","frontmatter":{},"headers":[],"relativePath":"ai-product-manager/role-overview.md","filePath":"ai-product-manager/role-overview.md","lastUpdated":1781090728000}'),h={name:"ai-product-manager/role-overview.md"};function u(g,t,p,B,q,m){const d=A("Mermaid");return a(),E("div",null,[t[2]||(t[2]=o('<h1 id="ai-pm-角色定位与三大方向" tabindex="-1">AI PM 角色定位与三大方向 <a class="header-anchor" href="#ai-pm-角色定位与三大方向" aria-label="Permalink to &quot;AI PM 角色定位与三大方向&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>AI 产品经理不是一个单一的岗位，而是已经分化出<strong>三个差异明显的专业方向</strong>。理解这些方向的核心差异、能力要求和适用人群，是转型 AI PM 的第一步。本章从职业定义、与传统 PM 的本质差异、三大方向对比、能力模型四个维度，帮你建立对 AI PM 角色的完整认知。</p><div class="tip custom-block"><p class="custom-block-title">学习目标</p><p>能清晰说出 AI PM 的三大方向及其核心差异，理解每个方向的能力要求和自己最适合的切入路径。</p></div><hr><h2 id="一、知识图谱" tabindex="-1">一、知识图谱 <a class="header-anchor" href="#一、知识图谱" aria-label="Permalink to &quot;一、知识图谱&quot;">​</a></h2>',6)),(a(),e(i,null,{default:r(()=>[n(d,{id:"mermaid-18",class:"mermaid",graph:"mindmap%0A%20%20root((AI%20PM%20%E8%A7%92%E8%89%B2%E5%AE%9A%E4%BD%8D))%0A%20%20%20%20AI%20PM%20vs%20%E4%BC%A0%E7%BB%9F%20PM%0A%20%20%20%20%20%20%E5%86%B3%E7%AD%96%E9%80%BB%E8%BE%91%E5%B7%AE%E5%BC%82%0A%20%20%20%20%20%20%E6%A0%B8%E5%BF%83%E9%A9%B1%E5%8A%A8%E5%B7%AE%E5%BC%82%0A%20%20%20%20%20%20%E8%BF%AD%E4%BB%A3%E6%A8%A1%E5%BC%8F%E5%B7%AE%E5%BC%82%0A%20%20%20%20%20%20%E6%8A%80%E6%9C%AF%E6%B7%B1%E5%BA%A6%E5%B7%AE%E5%BC%82%0A%20%20%20%20AI%20Native%20%E6%96%B9%E5%90%91%0A%20%20%20%20%20%20%E6%A0%B8%E5%BF%83%E8%83%BD%E5%8A%9B%0A%20%20%20%20%20%20%E5%85%B8%E5%9E%8B%E4%BA%A7%E5%93%81%0A%20%20%20%20%20%20%E5%B7%A5%E4%BD%9C%E5%86%85%E5%AE%B9%0A%20%20%20%20%20%20%E6%8C%91%E6%88%98%E4%B8%8E%E6%9C%BA%E4%BC%9A%0A%20%20%20%20AI%20%E5%B9%B3%E5%8F%B0%E6%96%B9%E5%90%91%0A%20%20%20%20%20%20%E6%A0%B8%E5%BF%83%E8%83%BD%E5%8A%9B%0A%20%20%20%20%20%20%E5%85%B8%E5%9E%8B%E4%BA%A7%E5%93%81%0A%20%20%20%20%20%20%E5%B7%A5%E4%BD%9C%E5%86%85%E5%AE%B9%0A%20%20%20%20%20%20%E6%8C%91%E6%88%98%E4%B8%8E%E6%9C%BA%E4%BC%9A%0A%20%20%20%20AI%2B%E8%A1%8C%E4%B8%9A%E6%96%B9%E5%90%91%0A%20%20%20%20%20%20%E6%A0%B8%E5%BF%83%E8%83%BD%E5%8A%9B%0A%20%20%20%20%20%20%E5%85%B8%E5%9E%8B%E5%9C%BA%E6%99%AF%0A%20%20%20%20%20%20%E5%B7%A5%E4%BD%9C%E5%86%85%E5%AE%B9%0A%20%20%20%20%20%20%E6%8C%91%E6%88%98%E4%B8%8E%E6%9C%BA%E4%BC%9A%0A%20%20%20%20%E8%83%BD%E5%8A%9B%E6%A8%A1%E5%9E%8B%0A%20%20%20%20%20%20%E6%8A%80%E6%9C%AF%E7%90%86%E8%A7%A3%E5%8A%9B%0A%20%20%20%20%20%20%E4%BA%A7%E5%93%81%E8%AE%BE%E8%AE%A1%E5%8A%9B%0A%20%20%20%20%20%20%E5%95%86%E4%B8%9A%E8%90%BD%E5%9C%B0%E5%8A%9B%0A%20%20%20%20%20%20%E4%BC%A6%E7%90%86%E5%90%88%E8%A7%84%E5%8A%9B%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=o('<hr><h2 id="二、ai-pm-与传统-pm-的本质差异" tabindex="-1">二、AI PM 与传统 PM 的本质差异 <a class="header-anchor" href="#二、ai-pm-与传统-pm-的本质差异" aria-label="Permalink to &quot;二、AI PM 与传统 PM 的本质差异&quot;">​</a></h2><h3 id="_2-1-核心差异对照表" tabindex="-1">2.1 核心差异对照表 <a class="header-anchor" href="#_2-1-核心差异对照表" aria-label="Permalink to &quot;2.1 核心差异对照表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>传统产品经理</th><th>AI 产品经理</th></tr></thead><tbody><tr><td><strong>决策逻辑</strong></td><td>确定性的 if/else 规则驱动</td><td>概率思维，管理模型输出的不确定性</td></tr><tr><td><strong>核心驱动</strong></td><td>功能逻辑 + 用户体验</td><td>数据 - 模型 - 场景的三角关系</td></tr><tr><td><strong>技术依赖深度</strong></td><td>API 调用级理解即可</td><td>深度掌握技术边界（模型能力上限、推理延迟、成本结构）</td></tr><tr><td><strong>迭代模式</strong></td><td>版本发布式迭代（双周/月度）</td><td>数据闭环持续迭代（天级别甚至实时）</td></tr><tr><td><strong>核心挑战</strong></td><td>需求优先级排序与体验优化</td><td>数据闭环构建 + 模型能力边界评估 + 技术商业价值权衡</td></tr><tr><td><strong>设计哲学</strong></td><td>确定性交互，每个按钮行为固定</td><td>概率化设计，每个节点需要 Fallback 降级机制</td></tr><tr><td><strong>PRD 核心</strong></td><td>功能规格 + 交互说明</td><td>功能规格 + 模型需求（输入/输出定义、置信度阈值、评估指标）</td></tr><tr><td><strong>测试方式</strong></td><td>功能测试（QA 点对点验证）</td><td>模型评估 + A/B 测试 + Bad Case 分析</td></tr></tbody></table><h3 id="_2-2-实战视角-工作量分布的真相" tabindex="-1">2.2 实战视角：工作量分布的真相 <a class="header-anchor" href="#_2-2-实战视角-工作量分布的真相" aria-label="Permalink to &quot;2.2 实战视角：工作量分布的真相&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">面试追问</p><p><strong>Q: 传统 PM 转型 AI PM，最大的不适应点是什么？</strong></p><p><strong>A:</strong> 我在转型初期最大的不适感来自两个地方。</p><p>第一，<strong>数据工作的比重远超预期</strong>。传统 PM 大概 70% 时间在写文档、对需求、跟开发沟通；但 AI PM 有 40% 的时间花在数据和标注上。你要跟标注团队定义标注规范、做一致性检验、分析 Bad Case、看数据分布变化。这不是传统 PM 的工作范畴，但它决定了模型能不能学到你想要的东西。</p><p>第二，<strong>&quot;上线不是终点，是起点&quot;</strong>。传统产品上线后代码是相对稳定的，但 AI 产品上线后模型一直在变——数据漂移会让准确率从 92% 掉到 85%，你得有监控和再训练的机制。我们之前一个风控模型，上线三个月后准确率掉了 7 个点，查下来是因为业务调整导致用户行为分布发生了变化（Concept Drift）。所以 AI PM 的工作状态更像&quot;运营&quot;，而不是&quot;交付&quot;。</p></div><hr><h2 id="三、三大方向详解" tabindex="-1">三、三大方向详解 <a class="header-anchor" href="#三、三大方向详解" aria-label="Permalink to &quot;三、三大方向详解&quot;">​</a></h2><h3 id="_3-1-ai-native-产品经理" tabindex="-1">3.1 AI Native 产品经理 <a class="header-anchor" href="#_3-1-ai-native-产品经理" aria-label="Permalink to &quot;3.1 AI Native 产品经理&quot;">​</a></h3><p><strong>定义</strong>：以 AI 为核心价值主张，创造全新产品品类。产品本身就是 AI——没有 AI 就不存在这个产品。</p><table tabindex="0"><thead><tr><th>要素</th><th>说明</th></tr></thead><tbody><tr><td><strong>典型产品</strong></td><td>ChatGPT、Kimi、Midjourney、Perplexity、Gamma</td></tr><tr><td><strong>核心用户</strong></td><td>C 端或 B 端的终端用户，他们&quot;用 AI&quot;而不是&quot;开发 AI&quot;</td></tr><tr><td><strong>核心工作</strong></td><td>Prompt 模板库设计、多模态交互设计、模型能力挖掘</td></tr><tr><td><strong>关键能力</strong></td><td>Prompt Engineering、UX 设计、模型能力边界评估、数据驱动迭代</td></tr><tr><td><strong>技术深度要求</strong></td><td>中等——不需要懂算法细节，但必须能准确判断模型能做什么、不能做什么</td></tr><tr><td><strong>典型公司</strong></td><td>月之暗面（Kimi）、智谱 AI（智谱清言）、MiniMax（海螺 AI）、OpenAI、Anthropic</td></tr></tbody></table><p><strong>实战案例</strong>：</p><blockquote><p>我在 AI Native 方向的实践中最大的体会是：<strong>PRD 文档被 Prompt 模板库替代了</strong>。以前我们写一个功能，PRD 里描述按钮放哪、交互逻辑是什么。现在做 AI Native 产品，设计的是一个 System Prompt——&quot;你是一个专业的数据分析师，当用户上传表格时，你应该先理解表格结构，再问用户想分析什么维度，然后...&quot;</p><p>Notion AI 的产品团队维护了一个 2000+ 变体的 Prompt 模板库，通过 A/B 测试来选出最优组合。你没法在 PRD 里写死&quot;输出什么格式、用什么语气&quot;，因为模型本身的输出是概率性的——你只能定义约束和期望，然后不断测试和迭代。</p><p>另一个关键能力是<strong>模型能力挖掘</strong>。GPT-4 最初没有被设计用于蛋白质结构预测，但产品经理与生物学家合作发现了这个突破性应用场景。AI Native PM 最值钱的地方，不是&quot;设计出多好看的交互&quot;，而是&quot;发现别人没发现的模型能力&quot;。</p></blockquote><h3 id="_3-2-ai-平台产品经理" tabindex="-1">3.2 AI 平台产品经理 <a class="header-anchor" href="#_3-2-ai-平台产品经理" aria-label="Permalink to &quot;3.2 AI 平台产品经理&quot;">​</a></h3><p><strong>定义</strong>：构建 AI 开发基础设施，用户是算法工程师和数据科学家。本质上是&quot;开发者的赋能者&quot;。</p><table tabindex="0"><thead><tr><th>要素</th><th>说明</th></tr></thead><tbody><tr><td><strong>典型产品</strong></td><td>百度千帆、阿里云 PAI、AWS SageMaker、MLflow、Weights &amp; Biases</td></tr><tr><td><strong>核心用户</strong></td><td>算法工程师、数据科学家、ML 工程师</td></tr><tr><td><strong>核心工作</strong></td><td>MLOps 工具链设计、训练/推理平台、数据管理平台</td></tr><tr><td><strong>关键能力</strong></td><td>分布式训练原理、模型服务化、开发者体验（DX）优化</td></tr><tr><td><strong>技术深度要求</strong></td><td>高——需要理解分布式训练（AllReduce）、推理加速（TensorRT）、GPU 显存管理</td></tr><tr><td><strong>典型公司</strong></td><td>百度智能云、阿里云、华为昇思、AWS、Google Cloud、Databricks</td></tr></tbody></table><p><strong>实战案例</strong>：</p><blockquote><p>AI 平台 PM 最特别的地方是——你的用户全是技术人，而且技术比你深。如果你不懂分布式训练，你跟算法团队开会时根本插不上话。</p><p>阿里云 PAI 产品经理面试时，有一道题是&quot;设计一个支持千卡并行的训练任务调度方案&quot;。你要考虑：任务如何切分到多张 GPU 上、AllReduce 通信的瓶颈在哪、训练中断后如何断点续训。传统 PM 不会遇到这种问题。</p><p>但这个方向有一大优势：<strong>职业壁垒极高</strong>。你懂的这些，纯产品背景的人学不会，纯技术背景的人又不愿意做产品。所以 AI 平台 PM 在市场上非常稀缺——2025 年的数据显示，这个方向的 HC 虽然比 AI Native 少，但薪资中位数更高，因为合格的候选人太少。</p></blockquote><h3 id="_3-3-ai-行业产品经理" tabindex="-1">3.3 AI+行业产品经理 <a class="header-anchor" href="#_3-3-ai-行业产品经理" aria-label="Permalink to &quot;3.3 AI+行业产品经理&quot;">​</a></h3><p><strong>定义</strong>：在现有业务中寻找 AI 赋能点，用 AI 技术改造传统业务流程。本质上是&quot;传统行业的智能化引擎&quot;。</p><table tabindex="0"><thead><tr><th>要素</th><th>说明</th></tr></thead><tbody><tr><td><strong>典型场景</strong></td><td>金融风控、医疗影像诊断、零售智能推荐、教育个性化学习、制造预测性维护</td></tr><tr><td><strong>核心用户</strong></td><td>行业内部的业务用户（医生、风控师、运营人员、质检员）</td></tr><tr><td><strong>核心工作</strong></td><td>技术选型决策、行业 AI 方案设计、变革管理（推动业务方接受 AI）</td></tr><tr><td><strong>关键能力</strong></td><td>行业 Know-how + 技术可行性判断 + ROI 测算 + 变革管理</td></tr><tr><td><strong>技术深度要求</strong></td><td>中等——需要理解什么技术能解决什么业务问题，但不需要深入算法细节</td></tr><tr><td><strong>典型公司</strong></td><td>平安科技（金融）、联影智能（医疗）、京东数科（零售）、美团（本地生活）</td></tr></tbody></table><p><strong>实战案例</strong>：</p><blockquote><p>AI+行业方向最考验的是&quot;翻译能力&quot;——把业务语言翻译成技术语言，再把技术边界翻译成业务语言。</p><p>我做过最典型的案例是零售场景的商品评价情感分析。业务方说&quot;我们要看用户对商品满不满意&quot;。这个需求听起来很简单，但拆开来看就复杂了——&quot;满意&quot;的定义是什么？给 3 星的评价说&quot;还行吧，一般般&quot;，算满意还是不满意？如果准确率从 85% 要求到 92%，解决方案可能从规则引擎变成 BERT 模型——但标注预算要增加 20 倍。你得跟业务方说清楚这笔账。</p><p>另一个重要能力是<strong>变革管理</strong>。医疗 AI 产品经理经常面对医生的抵触——&quot;AI 凭什么帮我做诊断？&quot;。腾讯觅影团队通过&quot;AI 辅助诊断→人机竞赛→共诊模式&quot;的三阶段推广策略，成功把三甲医院渗透率从 15% 拉到 68%。推动一个行业接受新技术，比设计技术本身更难。</p></blockquote><hr><h2 id="四、三大方向对比总结" tabindex="-1">四、三大方向对比总结 <a class="header-anchor" href="#四、三大方向对比总结" aria-label="Permalink to &quot;四、三大方向对比总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>AI Native</th><th>AI 平台</th><th>AI+行业</th></tr></thead><tbody><tr><td><strong>产品形态</strong></td><td>C 端 AI 应用</td><td>B 端 ML 基础设施</td><td>B 端行业解决方案</td></tr><tr><td><strong>用户画像</strong></td><td>终端消费者</td><td>算法/数据工程师</td><td>行业业务人员</td></tr><tr><td><strong>核心产出</strong></td><td>Prompt 模板库</td><td>MLOps 工具链</td><td>行业 AI 方案</td></tr><tr><td><strong>技术门槛</strong></td><td>中等</td><td>高</td><td>中等</td></tr><tr><td><strong>商业壁垒</strong></td><td>模型能力+网络效应</td><td>技术栈+迁移成本</td><td>行业 Know-how</td></tr><tr><td><strong>薪资区间</strong></td><td>30-80 万</td><td>40-100 万+</td><td>30-70 万</td></tr><tr><td><strong>适合背景</strong></td><td>C 端产品经验</td><td>算法/工程背景</td><td>行业经验+产品思维</td></tr></tbody></table><hr><h2 id="五、ai-pm-能力三角模型" tabindex="-1">五、AI PM 能力三角模型 <a class="header-anchor" href="#五、ai-pm-能力三角模型" aria-label="Permalink to &quot;五、AI PM 能力三角模型&quot;">​</a></h2>',28)),(a(),e(i,null,{default:r(()=>[n(d,{id:"mermaid-524",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5B%E6%8A%80%E6%9C%AF%E7%90%86%E8%A7%A3%E5%8A%9B%3Cbr%2F%3ETechnology%5D%20---%20B%5B%E4%BA%A7%E5%93%81%E8%AE%BE%E8%AE%A1%E5%8A%9B%3Cbr%2F%3EProduct%5D%0A%20%20%20%20B%20---%20C%5B%E5%95%86%E4%B8%9A%E8%90%BD%E5%9C%B0%E5%8A%9B%3Cbr%2F%3EBusiness%5D%0A%20%20%20%20C%20---%20A%0A%20%20%20%20A%20---%20D%5B%E4%BC%A6%E7%90%86%E5%90%88%E8%A7%84%E5%8A%9B%3Cbr%2F%3EEthics%5D%0A%20%20%20%20B%20---%20D%0A%20%20%20%20C%20---%20D%0A"})]),fallback:r(()=>[...t[1]||(t[1]=[s(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=o('<h3 id="_5-1-技术理解力" tabindex="-1">5.1 技术理解力 <a class="header-anchor" href="#_5-1-技术理解力" aria-label="Permalink to &quot;5.1 技术理解力&quot;">​</a></h3><ul><li>机器学习核心概念（监督/无监督/强化学习）</li><li>大模型原理（Token/Embedding/Attention）</li><li>模型能力边界评估</li><li>MLOps 基本认知</li></ul><p><strong>不要求</strong>：能写代码/能训练模型/能调参。</p><p><strong>必须做到</strong>：能判断&quot;这个需求用现有技术能不能做、多长时间能做出来、成本大概多少&quot;。</p><h3 id="_5-2-产品设计力" tabindex="-1">5.2 产品设计力 <a class="header-anchor" href="#_5-2-产品设计力" aria-label="Permalink to &quot;5.2 产品设计力&quot;">​</a></h3><ul><li>AI 产品需求分析方法（AI 适用性判断矩阵）</li><li>概率化 UX 设计（Fallback、降级策略、置信度显示）</li><li>Prompt 工程（System Prompt 设计、Few-shot 策略）</li><li>评估指标体系（模型指标 + 业务指标 + 体验指标）</li></ul><h3 id="_5-3-商业落地力" tabindex="-1">5.3 商业落地力 <a class="header-anchor" href="#_5-3-商业落地力" aria-label="Permalink to &quot;5.3 商业落地力&quot;">​</a></h3><ul><li>AI 商业模式设计（B2B/B2C/B2G 适配）</li><li>定价策略（按 Token/按效果/订阅制/混合制）</li><li>ROI 计算模型</li><li>GTM（Go-to-Market）策略</li></ul><h3 id="_5-4-伦理合规力" tabindex="-1">5.4 伦理合规力 <a class="header-anchor" href="#_5-4-伦理合规力" aria-label="Permalink to &quot;5.4 伦理合规力&quot;">​</a></h3><ul><li>AI 伦理原则（公平性、透明性、可解释性、隐私保护）</li><li>欧盟 AI 法案核心要求</li><li>中国生成式 AI 监管政策</li><li>偏见检测与缓解方案</li></ul><hr><h2 id="六、面试追问合集" tabindex="-1">六、面试追问合集 <a class="header-anchor" href="#六、面试追问合集" aria-label="Permalink to &quot;六、面试追问合集&quot;">​</a></h2><h3 id="q1-三大方向你觉得哪个最有前途-为什么" tabindex="-1">Q1: 三大方向你觉得哪个最有前途？为什么？ <a class="header-anchor" href="#q1-三大方向你觉得哪个最有前途-为什么" aria-label="Permalink to &quot;Q1: 三大方向你觉得哪个最有前途？为什么？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>短期（1-2 年）来说，<strong>AI Native 方向岗位最多、增长最快</strong>。2025 年中国 AI PM 岗同比增长 240%，其中大部分是 AI Native 方向——每个月之暗面、智谱、MiniMax 都在大量招人。</p><p>但长期（3-5 年），<strong>AI+行业才是最大的池子</strong>。因为 AI Native 的产品品类就那么多种——对话助手、搜索、创作工具、代码助手——头部效应很强，用户会集中在少数几个产品上。但 AI+行业几乎是无底洞——金融、医疗、教育、制造、能源、农业，每个行业都需要 AI 改造。而且行业知识的门槛让新人很难进来，一旦你在某个行业扎下根，职业安全感很强。</p><p>AI 平台方向市场总量不会特别大，但<strong>人均薪资最高</strong>——因为供给太少。如果你本身就是算法或工程背景，这个方向是就业&quot;压倒性优势&quot;的选择。</p></details><h3 id="q2-传统-pm-转型-ai-pm-最大的坑是什么" tabindex="-1">Q2: 传统 PM 转型 AI PM，最大的坑是什么？ <a class="header-anchor" href="#q2-传统-pm-转型-ai-pm-最大的坑是什么" aria-label="Permalink to &quot;Q2: 传统 PM 转型 AI PM，最大的坑是什么？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>最大的坑是<strong>用传统产品的思维工具去做 AI 产品</strong>。</p><p>具体说三个常见翻车场景：</p><ol><li><p><strong>&quot;这个功能下周上线&quot;</strong>：传统 PM 习惯了排期、开发、测试、上线的节奏。AI 产品你没法这样排。模型迭代的节奏取决于数据——可能调了三周准确率还在波动，也可能换了个 Embedding 模型突然提了 5 个点。不确定性是常态，严谨的排期在 AI 产品里就是自欺欺人。</p></li><li><p><strong>&quot;我把需求写清楚给算法，剩下的他们搞定&quot;</strong>：传统 PM 把 PRD 交给开发就很放心了。但 AI 产品的 PRD 不只是功能定义，还包括数据标注规范、评估指标、置信度阈值这些。你不定义清楚，算法帮你&quot;猜&quot;，猜出来的大概率不是你要的。</p></li><li><p><strong>&quot;在线上的模型再加个功能就行&quot;</strong>：传统产品加功能是增量开发；AI 产品加&quot;功能&quot;往往意味着重新定义模型输入/输出、重新标注数据、重新训练。你以为是一周的工作量，实际可能是一个月。</p></li></ol></details><h3 id="q3-产品经理需要会写代码吗" tabindex="-1">Q3: 产品经理需要会写代码吗？ <a class="header-anchor" href="#q3-产品经理需要会写代码吗" aria-label="Permalink to &quot;Q3: 产品经理需要会写代码吗？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>不需要会写生产级代码，但<strong>必须会写一些 Python 脚本用于数据分析、Prompt 测试、和 API 调用</strong>。</p><p>说一个具体的标准：你应该能独立完成以下三个任务——</p><ul><li>用 Python + Pandas 分析标注数据质量（标注一致性检查、类别分布统计）</li><li>用 OpenAI API 写一个 Prompt 测试脚本（批量跑 50 条测试用例看准确率）</li><li>用简单的 Streamlit / Gradio 搭建一个产品 Demo（不需要漂亮，但要能跑通核心功能）</li></ul><p>你不会这些的话，每次验证想法都要找工程师帮忙——你的迭代速度就比别人慢一个数量级。在 AI Native 公司，PM 自己撸 Python 是基本操作。</p></details><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./tech-basics">AI 技术基础</a></li><li><a href="./product-design">AI 产品设计</a></li><li><a href="./interview">AI PM 面试高频题</a></li></ul>',21))])}const b=l(h,[["render",u]]);export{P as __pageData,b as default};
